import{_ as a,o as i,c as o,a0 as l}from"./chunks/framework.ECMusB9M.js";const p=JSON.parse('{"title":"1. FICHAS","description":"","frontmatter":{},"headers":[],"relativePath":"Fichas/docs/temario/FICHA_04.md","filePath":"Fichas/docs/temario/FICHA_04.md"}'),d={name:"Fichas/docs/temario/FICHA_04.md"};function c(r,e,n,t,s,u){return i(),o("div",null,[...e[0]||(e[0]=[l('<h1 id="_1-fichas" tabindex="-1">1. FICHAS <a class="header-anchor" href="#_1-fichas" aria-label="Permalink to &quot;1. FICHAS&quot;">​</a></h1><h2 id="_1-1-ficha-04-el-canal-de-distribucion" tabindex="-1">1.1. FICHA 04 - EL CANAL DE DISTRIBUCIÓN <a class="header-anchor" href="#_1-1-ficha-04-el-canal-de-distribucion" aria-label="Permalink to &quot;1.1. FICHA 04 - EL CANAL DE DISTRIBUCIÓN&quot;">​</a></h2><blockquote><p><strong>INFO</strong><strong>Objetivo de la ficha</strong>: Definir el <code>canal de distribución</code> que va a usar la empresa.</p></blockquote><p>Basándote en tu idea de negocio, ¿cuál es el <code>canal de distribución</code> y la forma más adecuada para que tu producto llegue al cliente?</p><h3 id="_1-1-1-canal-directo" tabindex="-1">1.1.1. Canal directo <a class="header-anchor" href="#_1-1-1-canal-directo" aria-label="Permalink to &quot;1.1.1. Canal directo&quot;">​</a></h3><ol><li>¿Eres <code>fabricante</code> y vendes directamente a los clientes?</li><li>¿Vendes a través de: <ol><li><code>Internet</code>?</li><li><code>Página web</code>?</li><li><code>Tienda propia</code>?</li></ol></li></ol><h3 id="_1-1-2-canal-indirecto" tabindex="-1">1.1.2. Canal indirecto <a class="header-anchor" href="#_1-1-2-canal-indirecto" aria-label="Permalink to &quot;1.1.2. Canal indirecto&quot;">​</a></h3><ol><li>¿Vendes tus productos a: <ol><li><code>Mayoristas</code>?</li><li><code>Minoristas</code>?</li></ol></li><li>¿Eres un <code>minorista</code> que vende directamente al cliente?</li></ol><h3 id="_1-1-3-nuevas-formas-de-distribucion" tabindex="-1">1.1.3. Nuevas formas de distribución <a class="header-anchor" href="#_1-1-3-nuevas-formas-de-distribucion" aria-label="Permalink to &quot;1.1.3. Nuevas formas de distribución&quot;">​</a></h3><ol><li>¿Has pensado abrir una <code>franquicia</code>?</li><li>¿Vender, además, mediante: <ol><li><code>Comercio electrónico</code>?</li><li><code>Venta telefónica</code>?</li></ol></li></ol><h2 id="_1-2-ficha-04-actividades-de-promocion" tabindex="-1">1.2. FICHA 04 - ACTIVIDADES DE PROMOCIÓN <a class="header-anchor" href="#_1-2-ficha-04-actividades-de-promocion" aria-label="Permalink to &quot;1.2. FICHA 04 - ACTIVIDADES DE PROMOCIÓN&quot;">​</a></h2><blockquote><p><strong>INFO</strong><strong>Objetivo de la ficha</strong>: Concretar las <code>actividades de promoción</code> del producto.</p></blockquote><p>Basándote en tu idea de negocio, redacta las actividades de promoción que vas a llevar a cabo.</p><h3 id="_1-2-1-publicidad" tabindex="-1">1.2.1. Publicidad <a class="header-anchor" href="#_1-2-1-publicidad" aria-label="Permalink to &quot;1.2.1. Publicidad&quot;">​</a></h3><ol><li><p>¿Qué <code>medios de publicidad</code> crees que son los adecuados para tu empresa?</p><ol><li>¿Medios <code>masivos</code>?</li><li>¿<code>Buzoneo</code>?</li><li>¿<code>Internet</code>?</li><li>¿A través de la <code>página web</code>?</li><li>¿<code>Mailing</code>?</li><li>¿A través de <code>redes sociales</code>?</li></ol></li><li><p>Diseña un <code>folleto</code> de publicidad de una sola página donde se indiquen:</p><ol><li>Productos que vendes</li><li><code>Precios</code></li><li><code>Localización</code> de la empresa</li><li>Otros datos relevantes</li></ol><p>Intenta <strong>captar la atención</strong> y ser <code>creíble</code>.</p></li><li><p>Diseña también una <code>tarjeta de visita</code> que incluya:</p><ol><li>Tu <code>marca</code></li><li>Tus <code>datos de contacto</code></li></ol></li></ol><h3 id="_1-2-2-merchandising" tabindex="-1">1.2.2. Merchandising <a class="header-anchor" href="#_1-2-2-merchandising" aria-label="Permalink to &quot;1.2.2. Merchandising&quot;">​</a></h3><ol><li>¿Vendes en una <code>tienda</code> o <code>local</code>?</li><li>Indica las actividades relacionadas con: <ol><li><code>Rótulos</code></li><li><code>Escaparates</code></li><li><code>Carteles</code></li><li><code>Estanterías</code></li><li><code>Ambientación</code></li></ol></li></ol><h3 id="_1-2-3-promocion-de-ventas" tabindex="-1">1.2.3. Promoción de ventas <a class="header-anchor" href="#_1-2-3-promocion-de-ventas" aria-label="Permalink to &quot;1.2.3. Promoción de ventas&quot;">​</a></h3><ol><li>¿Puedes realizar promociones de corta duración como: <ol><li><code>Muestras</code></li><li><code>Regalos</code></li><li>Participación en <code>sorteos</code></li><li><code>2x1</code></li></ol></li></ol><h3 id="_1-2-4-fidelizacion" tabindex="-1">1.2.4. Fidelización <a class="header-anchor" href="#_1-2-4-fidelizacion" aria-label="Permalink to &quot;1.2.4. Fidelización&quot;">​</a></h3><ol><li>¿Qué piensas hacer para conservar tus <code>clientes</code>?</li><li>¿Qué puedes ofrecerles? <ol><li><code>Vales descuento</code></li><li><code>Puntos acumulables</code></li></ol></li></ol><h3 id="_1-2-5-relaciones-publicas" tabindex="-1">1.2.5. Relaciones públicas <a class="header-anchor" href="#_1-2-5-relaciones-publicas" aria-label="Permalink to &quot;1.2.5. Relaciones públicas&quot;">​</a></h3><ol><li>¿Puedes <code>patrocinar</code> alguna actividad que genere buena imagen para tu empresa?</li></ol><h3 id="_1-2-6-venta-directa" tabindex="-1">1.2.6. Venta directa <a class="header-anchor" href="#_1-2-6-venta-directa" aria-label="Permalink to &quot;1.2.6. Venta directa&quot;">​</a></h3><ol><li>¿Quién va a vender en tu empresa?</li><li>¿Qué actividades va a realizar? <ol><li><code>Persuadir</code> en la venta</li><li><code>Informar</code></li><li>Recoger <code>información</code></li></ol></li></ol>',25)])])}const m=a(d,[["render",c]]);export{p as __pageData,m as default};
